     1→import React, { useState } from 'react';
     2→import { User, ContentWriterInput, GeneratedContent, ContentVertical, ContentType } from '../types';
     3→import { generateContent } from '../services/content_writer';
     4→import { ArrowLeft, Feather, Copy, Download, Check, Loader2, RefreshCw, ShoppingBag, Cloud, Building, UtensilsCrossed, Heart, DollarSign, Scale, GraduationCap, Globe, FileText, Layout, Mail, Tag, Share2, Newspaper, BookOpen, Send, Sparkles } from 'lucide-react';
     5→
     6→interface Props {
     7→  onBack: () => void;
     8→  user: User | null;
     9→  onDeductCredits: (amount: number) => boolean;
    10→}
    11→
    12→const VERTICALS: { id: ContentVertical; label: string; icon: React.ElementType; color: string }[] = [
    13→  { id: 'ecommerce', label: 'E-commerce', icon: ShoppingBag, color: 'text-pink-400' },
    14→  { id: 'saas', label: 'SaaS', icon: Cloud, color: 'text-blue-400' },
    15→  { id: 'immobilier', label: 'Immobilier', icon: Building, color: 'text-amber-400' },
    16→  { id: 'restauration', label: 'Restauration', icon: UtensilsCrossed, color: 'text-orange-400' },
    17→  { id: 'sante', label: 'Sante', icon: Heart, color: 'text-red-400' },
    18→  { id: 'finance', label: 'Finance', icon: DollarSign, color: 'text-emerald-400' },
    19→  { id: 'juridique', label: 'Juridique', icon: Scale, color: 'text-purple-400' },
    20→  { id: 'education', label: 'Education', icon: GraduationCap, color: 'text-cyan-400' },
    21→  { id: 'general', label: 'General', icon: Globe, color: 'text-gray-400' },
    22→];
    23→
    24→const CONTENT_TYPES: { id: ContentType; label: string; icon: React.ElementType; cost: number }[] = [
    25→  { id: 'product_description', label: 'Fiche Produit', icon: FileText, cost: 2 },
    26→  { id: 'landing_page', label: 'Landing Page', icon: Layout, cost: 3 },
    27→  { id: 'sales_email', label: 'Email de Prospection', icon: Mail, cost: 2 },
    28→  { id: 'meta_tags', label: 'Kit Meta Tags', icon: Tag, cost: 1 },
    29→  { id: 'social_post', label: 'Posts Sociaux', icon: Share2, cost: 1 },
    30→  { id: 'press_release', label: 'Communique de Presse', icon: Newspaper, cost: 2 },
    31→  { id: 'case_study', label: 'Etude de Cas', icon: BookOpen, cost: 3 },
    32→  { id: 'newsletter', label: 'Newsletter', icon: Send, cost: 2 },
    33→];
    34→
    35→const TONES = [
    36→  { id: 'professionnel' as const, label: 'Professionnel' },
    37→  { id: 'decontracte' as const, label: 'Decontracte' },
    38→  { id: 'autoritaire' as const, label: 'Autoritaire' },
    39→  { id: 'empathique' as const, label: 'Empathique' },
    40→  { id: 'technique' as const, label: 'Technique' },
    41→];
    42→
    43→const ContentWriter: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
    44→  const [step, setStep] = useState<'vertical' | 'type' | 'form' | 'result'>('vertical');
    45→  const [selectedVertical, setSelectedVertical] = useState<ContentVertical>('general');
    46→  const [selectedType, setSelectedType] = useState<ContentType>('product_description');
    47→  const [isGenerating, setIsGenerating] = useState(false);
    48→  const [result, setResult] = useState<GeneratedContent | null>(null);
    49→  const [copied, setCopied] = useState(false);
    50→
    51→  // Form
    52→  const [brandName, setBrandName] = useState('');
    53→  const [brandUrl, setBrandUrl] = useState('');
    54→  const [productOrService, setProductOrService] = useState('');
    55→  const [targetAudience, setTargetAudience] = useState('');
    56→  const [tone, setTone] = useState<ContentWriterInput['tone']>('professionnel');
    57→  const [language, setLanguage] = useState<'fr' | 'en'>('fr');
    58→  const [additionalContext, setAdditionalContext] = useState('');
    59→
    60→  const currentTypeCost = CONTENT_TYPES.find(t => t.id === selectedType)?.cost || 2;
    61→
    62→  const handleGenerate = async () => {
    63→    if (!brandName || !productOrService || !targetAudience) {
    64→      alert("Veuillez remplir tous les champs obligatoires."); // TODO: Replace with sonner toast
    65→      return;
    66→    }
    67→
    68→    const canProceed = onDeductCredits(currentTypeCost);
    69→    if (!canProceed) return;
    70→
    71→    setIsGenerating(true);
    72→    try {
    73→      const output = await generateContent({
    74→        vertical: selectedVertical,
    75→        contentType: selectedType,
    76→        brandName,
    77→        brandUrl: brandUrl || undefined,
    78→        productOrService,
    79→        targetAudience,
    80→        tone,
    81→        language,
    82→        additionalContext: additionalContext || undefined,
    83→      });
    84→      setResult(output);
    85→      setStep('result');
    86→    } catch (error) {
    87→      console.error(error); // TODO: Replace with proper error reporting (Sentry)
    88→      alert("Erreur lors de la generation."); // TODO: Replace with sonner toast
    89→    } finally {
    90→      setIsGenerating(false);
    91→    }
    92→  };
    93→
    94→  const handleCopy = (text: string) => {
    95→    navigator.clipboard.writeText(text);
    96→    setCopied(true);
    97→    setTimeout(() => setCopied(false), 2000);
    98→  };
    99→
   100→  const handleDownload = (filename: string, content: string) => {
   101→    const blob = new Blob([content], { type: 'text/markdown' });
   102→    const url = URL.createObjectURL(blob);
   103→    const a = document.createElement('a');
   104→    a.href = url;
   105→    a.download = filename;
   106→    document.body.appendChild(a);
   107→    a.click();
   108→    document.body.removeChild(a);
   109→    URL.revokeObjectURL(url);
   110→  };
   111→
   112→  const handleRegenerate = () => {
   113→    setResult(null);
   114→    setStep('form');
   115→  };
   116→
   117→  // Score Ring mini inline
   118→  const ScoreRingMini = ({ score }: { score: number }) => {
   119→    const color = score >= 75 ? '#10b981' : score >= 50 ? '#f59e0b' : '#ef4444';
   120→    const circumference = 2 * Math.PI * 28;
   121→    const offset = circumference - (score / 100) * circumference;
   122→    return (
   123→      <div className="relative w-20 h-20">
   124→        <svg className="w-20 h-20 -rotate-90" viewBox="0 0 64 64">
   125→          <circle cx="32" cy="32" r="28" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="4" />
   126→          <circle cx="32" cy="32" r="28" fill="none" stroke={color} strokeWidth="4" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
   127→        </svg>
   128→        <div className="absolute inset-0 flex items-center justify-center">
   129→          <span className="text-lg font-bold text-white">{score}</span>
   130→        </div>
   131→      </div>
   132→    );
   133→  };
   134→
   135→  return (
   136→    <div className="max-w-5xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-screen">
   137→      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
   138→        <ArrowLeft size={18} className="mr-2" /> Retour
   139→      </button>
   140→
   141→      {/* Header */}
   142→      <div className="flex items-center gap-4 mb-10">
   143→        <div className="p-3 bg-rose-500/10 rounded-2xl">
   144→          <Feather size={32} className="text-rose-400" />
   145→        </div>
   146→        <div>
   147→          <h1 className="text-3xl font-bold text-white">AI Content Writer</h1>
   148→          <p className="text-gray-400">Redaction B2B optimisee AEO par vertical metier</p>
   149→        </div>
   150→        <span className="ml-auto bg-rose-500/10 text-rose-400 text-xs font-bold px-3 py-1 rounded-full border border-rose-500/20 flex items-center gap-1">
   151→          <Sparkles size={12} /> FRAMEWORK C.I.T.E.D.B.Y.
   152→        </span>
   153→      </div>
   154→
   155→      {/* Step 1: Select Vertical */}
   156→      {step === 'vertical' && (
   157→        <div>
   158→          <h2 className="text-xl font-bold text-white mb-6">1. Choisissez votre vertical metier</h2>
   159→          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
   160→            {VERTICALS.map(v => (
   161→              <button
   162→                key={v.id}
   163→                onClick={() => { setSelectedVertical(v.id); setStep('type'); }}
   164→                className="bg-[#1a1d21] border border-white/5 rounded-xl p-6 flex flex-col items-center gap-3 hover:bg-white/5 hover:border-rose-500/30 transition-all group"
   165→              >
   166→                <v.icon size={32} className={`${v.color} group-hover:scale-110 transition-transform`} />
   167→                <span className="text-sm font-bold text-gray-300 group-hover:text-white">{v.label}</span>
   168→              </button>
   169→            ))}
   170→          </div>
   171→        </div>
   172→      )}
   173→
   174→      {/* Step 2: Select Content Type */}
   175→      {step === 'type' && (
   176→        <div>
   177→          <div className="flex items-center gap-2 mb-2">
   178→            <button onClick={() => setStep('vertical')} className="text-gray-500 hover:text-white text-sm">&larr; Vertical</button>
   179→            <span className="text-gray-600 text-sm">/</span>
   180→            <span className="text-rose-400 text-sm font-medium">{VERTICALS.find(v => v.id === selectedVertical)?.label}</span>
   181→          </div>
   182→          <h2 className="text-xl font-bold text-white mb-6">2. Type de contenu</h2>
   183→          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
   184→            {CONTENT_TYPES.map(ct => (
   185→              <button
   186→                key={ct.id}
   187→                onClick={() => { setSelectedType(ct.id); setStep('form'); }}
   188→                className="bg-[#1a1d21] border border-white/5 rounded-xl p-5 flex flex-col items-center gap-3 hover:bg-white/5 hover:border-rose-500/30 transition-all group"
   189→              >
   190→                <ct.icon size={28} className="text-rose-400 group-hover:scale-110 transition-transform" />
   191→                <span className="text-xs font-bold text-gray-300 group-hover:text-white text-center">{ct.label}</span>
   192→                <span className="text-[10px] text-gray-500">{ct.cost} credits</span>
   193→              </button>
   194→            ))}
   195→          </div>
   196→        </div>
   197→      )}
   198→
   199→      {/* Step 3: Form */}
   200→      {step === 'form' && (
   201→        <div>
   202→          <div className="flex items-center gap-2 mb-2">
   203→            <button onClick={() => setStep('type')} className="text-gray-500 hover:text-white text-sm">&larr; Type</button>
   204→            <span className="text-gray-600 text-sm">/</span>
   205→            <span className="text-rose-400 text-sm font-medium">{CONTENT_TYPES.find(t => t.id === selectedType)?.label}</span>
   206→          </div>
   207→          <h2 className="text-xl font-bold text-white mb-6">3. Brief de generation</h2>
   208→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6 space-y-5">
   209→            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
   210→              <div>
   211→                <label className="block text-sm text-gray-400 mb-1.5">Nom de la marque *</label>
   212→                <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
   213→              </div>
   214→              <div>
   215→                <label className="block text-sm text-gray-400 mb-1.5">URL du site (optionnel)</label>
   216→                <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
   217→              </div>
   218→            </div>
   219→            <div>
   220→              <label className="block text-sm text-gray-400 mb-1.5">Produit ou Service *</label>
   221→              <input value={productOrService} onChange={e => setProductOrService(e.target.value)} placeholder="Ex: Plateforme d'optimisation AEO pour marques B2B" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
   222→            </div>
   223→            <div>
   224→              <label className="block text-sm text-gray-400 mb-1.5">Audience cible *</label>
   225→              <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="Ex: Directeurs marketing B2B, 50-500 employes" className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm" />
   226→            </div>
   227→            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
   228→              <div>
   229→                <label className="block text-sm text-gray-400 mb-1.5">Ton</label>
   230→                <select value={tone} onChange={e => setTone(e.target.value as any)} className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm">
   231→                  {TONES.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
   232→                </select>
   233→              </div>
   234→              <div>
   235→                <label className="block text-sm text-gray-400 mb-1.5">Langue</label>
   236→                <select value={language} onChange={e => setLanguage(e.target.value as 'fr' | 'en')} className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm">
   237→                  <option value="fr">Francais</option>
   238→                  <option value="en">English</option>
   239→                </select>
   240→              </div>
   241→              <div className="flex items-end">
   242→                <div className="bg-rose-500/10 border border-rose-500/20 rounded-lg px-4 py-3 text-center w-full">
   243→                  <span className="text-xs text-gray-400">Cout</span>
   244→                  <span className="block text-lg font-bold text-rose-400">{currentTypeCost} GTO</span>
   245→                </div>
   246→              </div>
   247→            </div>
   248→            <div>
   249→              <label className="block text-sm text-gray-400 mb-1.5">Contexte additionnel (optionnel)</label>
   250→              <textarea value={additionalContext} onChange={e => setAdditionalContext(e.target.value)} rows={3} placeholder="Informations supplementaires, contraintes, mots-cles cibles..." className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-rose-500/50 outline-none text-sm resize-none" />
   251→            </div>
   252→            <button
   253→              onClick={handleGenerate}
   254→              disabled={isGenerating || !brandName || !productOrService || !targetAudience}
   255→              className="w-full bg-rose-500 text-white font-bold py-3.5 rounded-xl hover:bg-rose-600 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
   256→            >
   257→              {isGenerating ? <><Loader2 size={18} className="animate-spin" /> Generation en cours...</> : <><Feather size={18} /> Generer le contenu</>}
   258→            </button>
   259→          </div>
   260→        </div>
   261→      )}
   262→
   263→      {/* Step 4: Result */}
   264→      {step === 'result' && result && (
   265→        <div>
   266→          <div className="flex items-center gap-2 mb-6">
   267→            <button onClick={handleRegenerate} className="text-gray-500 hover:text-white text-sm">&larr; Modifier le brief</button>
   268→          </div>
   269→
   270→          {/* Score + Meta */}
   271→          <div className="flex items-center gap-6 mb-8 bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
   272→            <ScoreRingMini score={result.aeoScore} />
   273→            <div className="flex-1">
   274→              <h3 className="text-lg font-bold text-white">{result.title}</h3>
   275→              {result.metaDescription && <p className="text-sm text-gray-400 mt-1">{result.metaDescription}</p>}
   276→            </div>
   277→            <div className="flex gap-2">
   278→              <button onClick={() => handleCopy(result.content)} className="p-2.5 bg-white/5 rounded-lg hover:bg-white/10 transition-colors" title="Copier">
   279→                {copied ? <Check size={16} className="text-emerald-400" /> : <Copy size={16} className="text-gray-400" />}
   280→              </button>
   281→              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 bg-white/5 rounded-lg hover:bg-white/10 transition-colors" title="Telecharger">
   282→                <Download size={16} className="text-gray-400" />
   283→              </button>
   284→              <button onClick={handleRegenerate} className="p-2.5 bg-white/5 rounded-lg hover:bg-white/10 transition-colors" title="Regenerer">
   285→                <RefreshCw size={16} className="text-gray-400" />
   286→              </button>
   287→            </div>
   288→          </div>
   289→
   290→          {/* AEO Tips */}
   291→          {result.aeoTips.length > 0 && (
   292→            <div className="mb-6 bg-rose-500/5 border border-rose-500/10 rounded-xl p-5">
   293→              <h4 className="text-sm font-bold text-rose-400 mb-3">Conseils AEO</h4>
   294→              <ul className="space-y-1.5">
   295→                {result.aeoTips.map((tip, i) => (
   296→                  <li key={i} className="text-sm text-gray-300 flex items-start gap-2">
   297→                    <span className="text-rose-400 mt-0.5">&#x2022;</span> {tip}
   298→                  </li>
   299→                ))}
   300→              </ul>
   301→            </div>
   302→          )}
   303→
   304→          {/* Content */}
   305→          <div className="bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
   306→            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 leading-relaxed">
   307→              {result.content}
   308→            </div>
   309→          </div>
   310→
   311→          {/* Schema Markup */}
   312→          {result.schemaMarkup && (
   313→            <div className="mt-6 bg-[#1a1d21] border border-white/5 rounded-2xl p-6">
   314→              <div className="flex items-center justify-between mb-3">
   315→                <h4 className="text-sm font-bold text-gray-200">Schema.org JSON-LD</h4>
   316→                <button onClick={() => handleCopy(result.schemaMarkup || '')} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
   317→                  <Copy size={12} /> Copier
   318→                </button>
   319→              </div>
   320→              <pre className="text-xs text-emerald-400 bg-black/40 rounded-lg p-4 overflow-x-auto">{result.schemaMarkup}</pre>
   321→            </div>
   322→          )}
   323→        </div>
   324→      )}
   325→    </div>
   326→  );
   327→};
   328→
   329→export default ContentWriter;
   330→

