     1→import React, { useState } from 'react';
     2→import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
     3→import { scanReputation, generateReputationResponse } from '../services/reputation_service';
     4→import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
     5→
     6→interface Props {
     7→  onBack: () => void;
     8→  user: User | null;
     9→  onDeductCredits: (amount: number) => boolean;
    10→}
    11→
    12→const AI_LOGOS: Record<string, string> = {
    13→  ChatGPT: 'bg-emerald-500/20 text-emerald-400',
    14→  Perplexity: 'bg-blue-500/20 text-blue-400',
    15→  Claude: 'bg-orange-500/20 text-orange-400',
    16→  Gemini: 'bg-purple-500/20 text-purple-400',
    17→  Copilot: 'bg-cyan-500/20 text-cyan-400',
    18→};
    19→
    20→const SENTIMENT_CONFIG = {
    21→  positive: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20', label: 'Positif' },
    22→  neutral: { color: 'text-gray-400', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    23→  negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Negatif' },
    24→};
    25→
    26→const SEVERITY_CONFIG = {
    27→  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
    28→  warning: { icon: AlertCircle, color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/20' },
    29→  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
    30→};
    31→
    32→const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
    33→  const [step, setStep] = useState<'form' | 'results'>('form');
    34→  const [isScanning, setIsScanning] = useState(false);
    35→  const [report, setReport] = useState<ReputationReport | null>(null);
    36→
    37→  // Form
    38→  const [brandName, setBrandName] = useState('');
    39→  const [brandUrl, setBrandUrl] = useState('');
    40→  const [industry, setIndustry] = useState('');
    41→  const [competitorInput, setCompetitorInput] = useState('');
    42→  const [competitors, setCompetitors] = useState<string[]>([]);
    43→  const [keywordInput, setKeywordInput] = useState('');
    44→  const [keywords, setKeywords] = useState<string[]>([]);
    45→
    46→  // Action plan
    47→  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
    48→  const [actionPlan, setActionPlan] = useState<string | null>(null);
    49→  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
    50→  const [copied, setCopied] = useState(false);
    51→
    52→  const addCompetitor = () => {
    53→    if (competitorInput.trim() && competitors.length < 5) {
    54→      setCompetitors([...competitors, competitorInput.trim()]);
    55→      setCompetitorInput('');
    56→    }
    57→  };
    58→
    59→  const addKeyword = () => {
    60→    if (keywordInput.trim() && keywords.length < 10) {
    61→      setKeywords([...keywords, keywordInput.trim()]);
    62→      setKeywordInput('');
    63→    }
    64→  };
    65→
    66→  const handleScan = async () => {
    67→    if (!brandName || !industry) {
    68→      alert("Veuillez remplir le nom de la marque et le secteur."); // TODO: Replace with sonner toast
    69→      return;
    70→    }
    71→
    72→    const canProceed = onDeductCredits(3);
    73→    if (!canProceed) return;
    74→
    75→    setIsScanning(true);
    76→    try {
