    76→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
    77→  const monthlyProjectCount = useMemo(() => {
    78→    if (history.length === 0) return 0;
    79→
    80→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
    81→    const now = new Date();
    82→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
    83→
    84→    // 1. Identifier la date de création (première analyse) de chaque domaine
    85→    const projectCreationDates = new Map<string, Date>();
    86→    
    87→    history.forEach(h => {
    88→        let hostname;
    89→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
    90→        
    91→        const analysisDate = new Date(h.timestamp);
    92→        
    93→        if (!projectCreationDates.has(hostname)) {
    94→            projectCreationDates.set(hostname, analysisDate);
    95→        } else {
    96→            // On garde la date la plus ancienne trouvée pour ce domaine
    97→            if (analysisDate < projectCreationDates.get(hostname)!) {
    98→                projectCreationDates.set(hostname, analysisDate);
    99→            }
   100→        }
   101→    });
   102→
   103→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
   104→    let count = 0;
   105→    projectCreationDates.forEach((creationDate) => {
   106→        if (creationDate >= billingCycleStart) {
   107→            count++;
   108→        }
   109→    });
   110→    
   111→    return count;
