   285→                ...prevHistory[index],
   286→                generatedSolutions: {
   287→                    ...(prevHistory[index].generatedSolutions || {}),
   288→                    [recommendationId]: solutionWithMeta
   289→                }
   290→            };
   291→            // Persist using db service
   292→            const newHistory = [...prevHistory];
